<div class="container">
    <header>
        <h1>FLF字体转ASCII艺术字生成器</h1>
    </header>

    <div class="main-content">
        <div class="upload-section">
            <div class="instructions">
                <h3>使用说明</h3>
                <p>1. 选择FIGlet字体文件</p>
                <p>2. 在下方输入要转换的文本</p>
                <p>3. 点击生成按钮创建ASCII艺术字</p>
                <p>4. 使用复制按钮将结果复制到剪贴板</p>
            </div>

            <div>
                <label for="inputText">输入要转换的文本:</label>
                <textarea id="inputText" rows="3" placeholder="输入要转换为ASCII艺术的文本">Hello World!</textarea>
                <div class="font-selector">
                    <label for="font-style">选择ASCII字体风格：</label>
                    <select id="font-style">
                    </select>
                </div>
                <button class="btn" id="generateBtn">生成ASCII艺术字</button>
                <button class="btn btn-secondary" id="copyBtn" disabled>复制结果</button>
            </div>
        </div>

        <div class="preview-section">
            <h2>预览</h2>
            <div id="preview" class="preview-box">ASCII艺术字将在这里显示...</div>
        </div>
    </div>
</div>


<script>
    class FLFParser {
        constructor() {
            this.metadata = null;
            this.fonts = {};
            this.commentLines = [];
        }

        /**
         * 解析FLF字体文件内容
         * @param {string} content - FLF文件的文本内容
         * @returns {Object} 解析后的字体数据
         */
        parse(content) {
            // 清除之前的解析结果
            this.metadata = null;
            this.fonts = {};
            this.commentLines = [];

            // 按行分割内容
            const lines = content.split('\n')
            // .map(line => line.trimEnd()) // 移除行尾空白
            // .filter(line => line !== ''); // 过滤空行
            if (lines.length === 0) {
                throw new Error('无效的FLF文件，内容为空');
            }

            // 解析头部标识行
            this._parseHeader(lines[0]);
            // 解析注释行
            const commentLinesCount = Math.max(0, this.metadata.commentLines);
            for (let i = 1; i <= commentLinesCount && i < lines.length; i++) {
                this.commentLines.push(lines[i]);
            }

            // 解析字符数据（跳过头部和注释行）
            const charDataLines = lines.slice(1 + commentLinesCount);
            this._parseCharacters(charDataLines);
            return {
                metadata: this.metadata,
                commentLines: this.commentLines,
                fonts: this.fonts
            };
        }
        /**
         * 解析头部标识行
         * 格式: flf2a$ 高度 基线 最大宽度 注释行数 字符间距
         */
        _parseHeader(headerLine) {

            const parts = headerLine.split(/\s+/);
            if (parts.length < 6) {
                throw new Error('FLF文件头格式不正确');
            }

            this.metadata = {
                signature: parts[0],
                height: parseInt(parts[1], 10),
                baseline: parseInt(parts[2], 10),
                maxWidth: parseInt(parts[3], 10),
                charSpacing: parseInt(parts[4], 10),
                commentLines: parseInt(parts[5], 10)
            };
            // 验证数值有效性
            Object.keys(this.metadata).forEach(key => {
                if (key !== 'signature' && isNaN(this.metadata[key])) {
                    throw new Error(`FLF文件头参数无效: ${key}`);
                }
            });
        }
        /**
         * 解析头部标识行
         * 格式: flf2a$ 高度 基线 最大宽度 注释行数 字符间距
         * 解析字符数据
         */
        _parseCharacters(lines) {
            const { height } = this.metadata;
            let currentCharCode = 32; // 从空格字符开始 (ASCII 32)
            let currentCharLines = [];
            for (const line of lines) {
                const cleanedLine = line.replace(/@|\$/g, '');
                currentCharLines.push(cleanedLine);
                // 当收集到足够的行数（等于字体高度），表示一个字符解析完成
                if (currentCharLines.length === height) {
                    // 将字符添加到字体映射表
                    const char = String.fromCharCode(currentCharCode);
                    this.fonts[char] = [...currentCharLines];

                    // 重置并准备解析下一个字符
                    currentCharLines = [];
                    currentCharCode++;
                }
            }
        }

        /**
         * 使用解析后的字体生成ASCII艺术
         * @param {string} text - 要转换的文本
         * @returns {string} 生成的ASCII艺术
         */
        generateAsciiArt(text) {
            if (!this.metadata || Object.keys(this.fonts).length === 0) {
                throw new Error('请先解析FLF字体文件');
            }

            const { height } = this.metadata;
            const resultLines = Array(height).fill('');
            for (const char of text) {
                const charLines = this.fonts[char] || this.fonts[' '] || Array(height).fill('');
                for (let i = 0; i < height; i++) {
                    resultLines[i] += charLines[i] +" "|| '';
                    resultLines[i] = resultLines[i].replace(/\r|#/g, '')
                    // resultLines[i] += ' '.repeat(Math.max(1, 2));
                }

            }
            return resultLines.join('\n');
        }
    }
    const parser = new FLFParser();

    document.addEventListener('DOMContentLoaded', function () {

        const fontStyle = document.getElementById('font-style');
        const generateBtn = document.getElementById('generateBtn');
        const copyBtn = document.getElementById('copyBtn');
        const inputText = document.getElementById('inputText');
        const maxWidth = document.getElementById('maxWidth');
        const preview = document.getElementById('preview');
        const successMessage = document.getElementById('successMessage');

        let currentFont = null;


        // 生成按钮点击事件
        generateBtn.addEventListener('click', generateAsciiArt);

        // 复制按钮点击事件
        copyBtn.addEventListener('click', copyToClipboard);


        // 生成ASCII艺术字
        async  function generateAsciiArt() {
            const text = inputText.value.trim();
            if (!text) {
                alert('请输入要转换的文本');
                return;
            }
            try {
                // let flf = getrandom(window.config.flf)

                let flf= fontStyle.value
                const res = await fetch('/fonts/'+flf);
                const flfContent = await res.text();
                const fontData = parser.parse(flfContent);
                const asciiArt = parser.generateAsciiArt(text);
                console.log(asciiArt)
                preview.textContent = asciiArt;
                copyBtn.disabled = false;
            } catch (error) {
                alert('生成ASCII艺术字时出错: ' + error.message);
            }
        }


        // 复制到剪贴板
        function copyToClipboard() {
            const text1 = preview.textContent;
            navigator.clipboard.writeText(text1).then(() => {
                   alert('复制成功');
            }).catch(err => {
                alert('复制失败: ' + err);
            });
        }
    });

</script>
